example.code:
import structlog import uuid
logger = structlog.get_logger()
@app.middleware("http") async def logging_middleware(request, call_next): request_id = str(uuid.uuid4()) request.state.request_id = request_id log = logger.bind(request_id=request_id, method=request.method, path=request.url.path) log.info("request_started") import time; start = time.time() try: response = await call_next(request) log.info("request_completed", status=response.status_code, duration_ms=round((time.time() - start) * 1000, 2)) response.headers["X-Request-ID"] = request_id return response except Exception as e: log.error("request_failed", error=str(e)) raise
